"""holdout CLI — drop `holdout check` in CI to block shipping noise.

    holdout check candidate.jsonl --baseline baseline.jsonl --variants 37
    holdout check paired.jsonl --paired            # one file with baseline+candidate columns
    holdout power --baseline-acc 0.75 --effect 0.03

`check` exits non-zero when the improvement is not a significant gain (the CI gate).
"""
from __future__ import annotations

import argparse
import json
import sys

from . import __version__
from .compare import compare
from .io import align, load_paired, load_scores
from .stats import fwer, required_n


def _cmd_check(args) -> int:
    if args.paired:
        base, cand = load_paired(args.candidate, args.baseline_field, args.candidate_field)
        info = {"n_shared": len(base)}
    else:
        if not args.baseline:
            print("error: provide --baseline FILE, or --paired for a single combined file",
                  file=sys.stderr)
            return 2
        b = load_scores(args.baseline, score_field=args.score_field)
        c = load_scores(args.candidate, score_field=args.score_field)
        base, cand, info = align(b, c)

    res = compare(base, cand, variants_tried=args.variants, alpha=args.alpha,
                  ci_level=args.ci, n_resamples=args.resamples, seed=args.seed, test=args.test)

    if args.json:
        out = res.to_dict()
        out["align"] = info
        print(json.dumps(out, indent=2))
    else:
        if info.get("n_baseline_only") or info.get("n_candidate_only"):
            print(f"  note: matched {info['n_shared']} tasks "
                  f"(dropped {info.get('n_baseline_only', 0)} baseline-only, "
                  f"{info.get('n_candidate_only', 0)} candidate-only)\n")
        print(res.report())

    return 0 if res.significant else 1


def _cmd_power(args) -> int:
    n = required_n(args.effect, baseline_acc=args.baseline_acc, alpha=args.alpha,
                   power=args.power, paired_corr=args.corr)
    if args.json:
        print(json.dumps({
            "required_n": n, "effect": args.effect, "baseline_acc": args.baseline_acc,
            "alpha": args.alpha, "power": args.power, "paired_corr": args.corr,
        }, indent=2))
    else:
        print(f"  To detect a {args.effect * 100:+.1f} pt change at {args.baseline_acc * 100:.0f}% "
              f"baseline, {int(args.power * 100)}% power, alpha {args.alpha}:")
        print(f"  -> ~{n} tasks  (paired, assumed corr {args.corr})")
        if args.variants > 1:
            print(f"  Across {args.variants} variants, P(>=1 false win) at alpha {args.alpha} "
                  f"= {fwer(args.variants, args.alpha) * 100:.0f}%.")
    return 0


def build_parser() -> argparse.ArgumentParser:
    p = argparse.ArgumentParser(prog="holdout",
                                description="An independent significance referee for evals.")
    p.add_argument("--version", action="version", version=f"holdout {__version__}")
    sub = p.add_subparsers(dest="cmd", required=True)

    c = sub.add_parser("check", help="is a candidate a real improvement over a baseline?")
    c.add_argument("candidate", help="JSONL of per-task scores for the candidate")
    c.add_argument("--baseline", help="JSONL of per-task scores for the baseline")
    c.add_argument("--paired", action="store_true",
                   help="single file with baseline & candidate columns per row")
    c.add_argument("--variants", type=int, default=1,
                   help="how many variants you tried before reporting this one")
    c.add_argument("--alpha", type=float, default=0.05)
    c.add_argument("--ci", type=float, default=0.95)
    c.add_argument("--resamples", type=int, default=10000)
    c.add_argument("--seed", type=int, default=0)
    c.add_argument("--test", choices=["auto", "mcnemar_exact", "paired_permutation"],
                   default="auto")
    c.add_argument("--score-field", default=None)
    c.add_argument("--baseline-field", default="baseline")
    c.add_argument("--candidate-field", default="candidate")
    c.add_argument("--json", action="store_true")
    c.set_defaults(func=_cmd_check)

    pw = sub.add_parser("power", help="how many tasks do you need?")
    pw.add_argument("--baseline-acc", type=float, default=0.5)
    pw.add_argument("--effect", type=float, required=True, help="effect size, e.g. 0.03 for 3pp")
    pw.add_argument("--alpha", type=float, default=0.05)
    pw.add_argument("--power", type=float, default=0.8)
    pw.add_argument("--corr", type=float, default=0.5)
    pw.add_argument("--variants", type=int, default=1)
    pw.add_argument("--json", action="store_true")
    pw.set_defaults(func=_cmd_power)
    return p


def main(argv=None) -> int:
    args = build_parser().parse_args(argv)
    try:
        return args.func(args)
    except (ValueError, KeyError, FileNotFoundError, json.JSONDecodeError) as e:
        print(f"error: {e}", file=sys.stderr)
        return 2


if __name__ == "__main__":
    raise SystemExit(main())
